const p = $input.first().json;
const tierLabels = { 1: 'Tier 1 (Phone Verified)', 2: 'Tier 2 (ID + Selfie)', 3: 'Tier 3 (Full KYC)' };
const tierName = tierLabels[p.tier] || `Tier ${p.tier}`;
return [{
  json: {
    to: p.user_email,
    subject: `Your identity verification has been approved — ${tierName}`,
    body: `Congratulations! Your KYC verification has been approved.\n\nVerification level: ${tierName}\nApproved at: ${p.reviewed_at}\n\nYou can now use the platform features unlocked by your verification level.\nLog in to your account: ${process.env.APP_BASE_URL}`
  }
}];
